function solve(n: number): number {
    // Helper function to check if a number is a palindrome
    function isPalindrome(num: number): boolean {
        const str = num.toString();
        return str === str.split('').reverse().join('');
    }

    // Helper function to check if a number meets the exact count condition
    function isValid(num: number): boolean {
        const count: { [key: string]: number } = {};
        const str = num.toString();
        for (const ch of str) {
            const digit = parseInt(ch, 10);
            if (digit === 0) continue; // Skip zero as it cannot appear exactly 0 times
            count[digit] = (count[digit] || 0) + 1;
        }
        for (const key in count) {
            if (count[key] !== parseInt(key, 10)) {
                return false;
            }
        }
        return true;
    }

    // Start checking from n + 1
    let candidate = n + 1;
    while (true) {
        if (isPalindrome(candidate) && isValid(candidate)) {
            return candidate;
        }
        candidate++;
    }
}

